from typing import List

class Solution:
    def minOperations(self, nums1: List[int], nums2: List[int]) -> int:
        n = len(nums1)
        max1 = max(nums1)
        max2 = max(nums2)

        # Check if the final condition is already satisfied
        if nums1[-1] == max1 and nums2[-1] == max2:
            return 0

        # Check if it's impossible to satisfy the conditions
        if nums1[-1] < max1 or nums2[-1] < max2:
            return -1

        # Greedy approach: iterate from the end to the beginning
        operations = 0
        for i in range(n - 1, -1, -1):
            # If nums1[i] is not the max in nums1, and nums2[i] is the max in nums2
            if nums1[i] < max1 and nums2[i] == max2:
                # Swap to make nums1[i] the max in nums1
                nums1[i], nums2[i] = nums2[i], nums1[i]
                operations += 1
            # If nums2[i] is not the max in nums2, and nums1[i] is the max in nums1
            elif nums2[i] < max2 and nums1[i] == max1:
                # Swap to make nums2[i] the max in nums2
                nums1[i], nums2[i] = nums2[i], nums1[i]
                operations += 1

        # Final check
        if nums1[-1] == max(nums1) and nums2[-1] == max(nums2):
            return operations
        else:
            return -1
